mapper.insert:
	insert into movmov_community_posts
	(post_no
	 , user_id
  	 , post_header
 	 , post_board_type
   	 , post_title
     , post_content
     , post_is_spoiler)
	values
	(POST_NO_SEQ.NEXTVAL
	 , #{user.id}
	 , #{header.id}
	 , #{boardType.id}
	 , #{title}
	 , #{content}
	 , #{isSpoiler})

update movmov_community_posts
set
	post_view_count = #{viewCount}
  , post_upvote_count = #{upvoteCount}
where
	post_no = #{no}

mapper.select:
select P.post_no , P.post_title , P.post_content , P.post_created_date , P.post_updated_date , P.post_view_count , P.post_upvote_count , P.post_is_spoiler , NVL(C.comment_count, 0) as commentCount , U.user_nickname as user_nickname , HC.cat_id as header_cat_id , HC.cat_name as header_cat_name , BC.cat_id as board_cat_id , BC.cat_name as board_cat_name from movmov_community_posts P left join (select post_no, count(*) as comment_count from movmov_community_comments group by post_no) C on P.post_no = C.post_no join movmov_content_categories HC on P.post_header = HC.cat_id join movmov_content_categories BC on P.post_board_type = BC.cat_id join movmov_users U on P.user_id = U.user_id where P.post_is_deleted = 'N'
and P.post_board_type = #{boardId}
and P.post_is_spoiler = #{spoiler}
and P.post_is_spoiler in #{header}
order by
P.post_no desc
P.post_no asc
P.post_no desc
offset #{offset} rows fetch next #{rows} rows only
